<template>
  <div class="hello">
    <md-button class="md-raised" v-on:click="onConnect">Connect</md-button>
    <img v-bind:src="idPhotoUrl"></img>
  </div>
</template>

<script>
import EID from '../eid';
console.log(EID);
export default {
  name: 'hello',
  data () {
    return {
      eid: null,
      photo: null
    };
  },
  created () {
    console.log('created');
  },
  computed: {
    idPhotoUrl () {
      if (this.photo) {
        var urlCreator = window.URL || window.webkitURL;
        return urlCreator.createObjectURL(this.photo);
      } else {
        return '';
      }
    }
  },
  methods: {
    onConnect () {
      if (this.eid) {
        this.eid.exit();
        this.eid = null;
      }
      console.log(navigator);
      navigator.usb.requestDevice({filters: []})
      .then(selectedDevice => {
        this.eid = new EID(selectedDevice);
        this.eid.on('card-inserted', this.onCardInserted);
        this.eid.init();
      });
    },
    onCardInserted () {
      console.log('card inserted');
      this.eid.idGetPhoto().then((blob) => {
        this.photo = blob;
      });
    }
  },
  watch: {

  }
};
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}

ul {
  list-style-type: none;
  padding: 0;
}

li {
  display: inline-block;
  margin: 0 10px;
}

a {
  color: #42b983;
}
</style>



